import{Base}from"./Base.js";import{random}from"../tools/random.js";class Handle extends Base{constructor(){super(),this.defaultFrom=()=>[this.parentNode],this.defaultTo=()=>[this.parentNode],this.defaultEvent="blam"}stringNumBool(string){try{return JSON.parse(string)}catch{return!Number(string)&&"0"!==string?string:parseFloat(string)}}setToFrom(){this.fromElems=this.from?[...document.querySelectorAll(this.from)]:this.defaultFrom(),this.toElems=this.to?[...document.querySelectorAll(this.to)]:this.defaultTo()}onblamready(){this.setToFrom(),this.listen()}handleEvent(event){event.type!==this.event||this.bypass?super.handleEvent(event):this.handle(event)}listen(){if(this.fromElems?.length&&this.toElems?.length)for(const from of this.fromElems)from.addEventListener(this.event,this)}unlisten(){for(const from of this.fromElems)from.removeEventListener(this.event,this)}get from(){return this.getAttribute("from")}set from(value){this.setAttribute("from",value)}get to(){return this.getAttribute("to")}set to(value){this.setAttribute("to",value)}get event(){return this.getAttribute("event")||this.defaultEvent}set event(value){this.setAttribute("event",value)}get prop(){return this.getAttribute("prop")}set prop(value){this.setAttribute("prop",value)}get bypass(){return this.hasAttribute("bypass")}set bypass(value){this.toBoolean("bypass",value)}get chance(){let value=this.getAttribute("chance");return value?parseFloat(value):1}set chance(value){this.setAttribute("chance",value)}connectedCallback(){this.listen()}disconnectedCallback(){this.unlisten()}}export{Handle};